fn main() {
    let mut x = 10;

    // Creating raw pointers is safe
    let ptr_const: *const i32 = &x;
    let ptr_mut: *mut i32 = &mut x;

    // Dereferencing requires unsafe
    unsafe {
        println!("const ptr: {}", *ptr_const);
        *ptr_mut = 20;
        println!("after mutation: {}", *ptr_mut);
    }

    // Raw pointers from addresses (dangerous!)
    let address = 0x012345usize;
    let _wild_ptr = address as *const i32;
    // Dereferencing this would be undefined behavior!
}

// This is how the standard library implements split_at_mut
// It needs unsafe because Rust cannot prove the two slices don't overlap
fn split_at_mut(slice: &mut [i32], mid: usize) -> (&mut [i32], &mut [i32]) {
    let len = slice.len();
    let ptr = slice.as_mut_ptr();

    assert!(mid <= len, "mid out of bounds");

    unsafe {
        (
            std::slice::from_raw_parts_mut(ptr, mid),
            std::slice::from_raw_parts_mut(ptr.add(mid), len - mid),
        )
    }
}

fn main() {
    let mut data = vec![1, 2, 3, 4, 5];
    let (left, right) = split_at_mut(&mut data, 3);
    left[0] = 10;
    right[0] = 40;
    println!("left: {:?}, right: {:?}", left, right);
    // left: [10, 2, 3], right: [40, 5]
}

fn safe_deref(ptr: *const i32) -> Option<i32> {
    if ptr.is_null() {
        None
    } else {
        unsafe { Some(*ptr) }
    }
}

fn main() {
    let x = 42;
    let valid: *const i32 = &x;
    let null: *const i32 = std::ptr::null();

    println!("valid: {:?}", safe_deref(valid));   // Some(42)
    println!("null: {:?}", safe_deref(null));      // None
}
